// Build a globe feed from user_vectors by finding matched pairs.
// Uses stored city/lat/lng when available (real users); falls back to
// a deterministic hub for demo_* rows with no coords.

const HUBS = [
  { name: 'Copenhagen', lat: 55.6761, lng:  12.5683 },
  { name: 'Stockholm',  lat: 59.3293, lng:  18.0686 },
  { name: 'Berlin',     lat: 52.5200, lng:  13.4050 },
  { name: 'London',     lat: 51.5074, lng:  -0.1278 },
  { name: 'Paris',      lat: 48.8566, lng:   2.3522 },
  { name: 'Amsterdam',  lat: 52.3676, lng:   4.9041 },
  { name: 'New York',   lat: 40.7128, lng: -74.0060 },
  { name: 'Los Angeles',lat: 34.0522, lng:-118.2437 },
  { name: 'Sao Paulo',  lat:-23.5505, lng: -46.6333 },
  { name: 'Tokyo',      lat: 35.6762, lng: 139.6503 },
  { name: 'Seoul',      lat: 37.5665, lng: 126.9780 },
  { name: 'Shanghai',   lat: 31.2304, lng: 121.4737 },
  { name: 'Singapore',  lat:  1.3521, lng: 103.8198 },
  { name: 'Sydney',     lat:-33.8688, lng: 151.2093 },
  { name: 'Mumbai',     lat: 19.0760, lng:  72.8777 },
  { name: 'Nairobi',    lat: -1.2921, lng:  36.8219 },
  { name: 'Cairo',      lat: 30.0444, lng:  31.2357 }
];
function djb2(s){let h=5381;for(let i=0;i<s.length;i++)h=((h<<5)+h)+s.charCodeAt(i);return h>>>0;}
function hubFor(sid){
  const biasList=[0,0].concat(HUBS.map((_,i)=>i));
  const idx=biasList[djb2(String(sid))%biasList.length];
  const c=HUBS[idx];
  const jitter=(v,spread)=>v+(((djb2(String(sid)+'_'+spread)%1000)/1000-0.5)*spread);
  return { name:c.name, lat:+jitter(c.lat,3).toFixed(4), lng:+jitter(c.lng,3).toFixed(4) };
}
function placeFor(r) {
  const lat=Number(r.lat), lng=Number(r.lng);
  if (Number.isFinite(lat) && Number.isFinite(lng) && !(lat===0 && lng===0)) {
    return { name: String(r.city || '').trim() || 'unknown', lat:+lat.toFixed(4), lng:+lng.toFixed(4) };
  }
  return hubFor(r.session_id);
}

const q = $('Webhook').first().json.query || {};
const sinceMs = q.since ? Date.parse(q.since) : 0;
const limit = Math.max(1, Math.min(200, Number(q.limit) || 50));

const rows = $input.all().map(i => i.json);
const bySid = new Map();
for (const r of rows) {
  const sid = String(r.session_id || '').trim();
  if (sid) bySid.set(sid, r);
}

const seenPair = new Set();
const matches = [];
for (const r of rows) {
  const sid = String(r.session_id || '').trim();
  const partnerSid = String(r.matched_user_id || '').trim();
  if (!sid || !partnerSid) continue;
  const mt = r.match_timestamp ? Date.parse(r.match_timestamp) : 0;
  if (!mt) continue;
  if (mt <= sinceMs) continue;
  const pairKey = [sid, partnerSid].sort().join('__');
  if (seenPair.has(pairKey)) continue;
  seenPair.add(pairKey);

  const partner = bySid.get(partnerSid);
  if (!partner) continue;

  const from = placeFor(r);
  const to   = placeFor(partner);
  if (from.lat === to.lat && from.lng === to.lng) {
    to.lng = +(to.lng + 6).toFixed(4);
  }

  const mode = (String(r.match_mode || 'echo').toLowerCase().trim() === 'healing') ? 'healing' : 'echo';
  const final_P = Number(r.final_P) || 0;
  const final_A = Number(r.final_A) || 0;
  const intensity = +Math.min(1, 0.35 + Math.abs(final_A) * 0.9).toFixed(3);

  matches.push({
    match_pair_id: pairKey,
    mode,
    final_P,
    final_A,
    intensity,
    timestamp: r.match_timestamp,
    from: { lat: from.lat, lng: from.lng, city: from.name },
    to:   { lat: to.lat,   lng: to.lng,   city: to.name }
  });
}

matches.sort((a, b) => Date.parse(b.timestamp) - Date.parse(a.timestamp));
return [{ json: { matches: matches.slice(0, limit), count: matches.length, now: new Date().toISOString() } }];
